function About() {
  return (
    <section id="about" className="p-20 bg-gray-900">
      <h2 className="text-3xl font-bold text-green-400 mb-6">About Me</h2>
      <p className="max-w-3xl">
        {/* I'm a MERN Stack Developer with 6 months of internship experience.
        I specialize in building full-stack applications using MongoDB,
        Express, React, and Node.js. */}
        I am a passionate MERN Stack Developer with hands-on internship experience at Ypsilon IT Solutions Pvt. Ltd., where I worked on building dynamic and scalable full-stack web applications using MongoDB, Express.js, React.js, and Node.js.

During my internship, I collaborated with development teams to design responsive user interfaces, developed secure REST APIs, and implemented efficient backend logic to ensure seamless application performance.

I have successfully built and deployed a full-stack E-commerce platform (ShopNix) featuring product listing, authentication, cart management, and order handling. I am passionate about writing clean code, solving backend challenges, and continuously improving my system design and development skills.
      </p>
    </section>
  );
}

export default About;
